agent-browser eval "
// Get total answers count from answers header
const answersHeader = document.querySelector('#answers-header h2, #answers h2, [data-answercount]');
if (answersHeader) {
  answersHeader.textContent.trim();
} else {
  // Try alternate selectors
  const alt = document.querySelector('.answers-subheader h2');
  alt ? alt.textContent.trim() : 'not found';
}
"

agent-browser eval "
// Confirm the vote count with data-value attribute
const accepted = document.querySelector('.js-accepted-answer');
const voteEl = accepted ? accepted.querySelector('.js-vote-count') : null;
JSON.stringify({
  dataValue: voteEl ? voteEl.getAttribute('data-value') : null,
