});
"

agent-browser eval "
// Scroll the accepted answer into view
const accepted = document.querySelector('.js-accepted-answer');
accepted ? accepted.scrollIntoView({behavior: 'instant', block: 'start'}) : 'not found';
'scrolled';
"

agent-browser eval "
// Double-check the author - look for the last user card (answerer, not editor)
const accepted = document.querySelector('.js-accepted-answer');
const userCards = accepted ? accepted.querySelectorAll('.post-signature') : [];
const authors = [];
userCards.forEach(card => {
  const link = card.querySelector('.user-details a');
  if (link) authors.push(link.textContent.trim());
});
JSON.stringify(authors);
"

agent-browser eval "
// Mysticial is the original author; Peter Cordes may be editor. Check the answerer specifically.
const accepted = document.querySelector('.js-accepted-answer');
// The answerer is typically in the last .post-signature that has 'answered' text nearby
const sigs = accepted ? accepted.querySelectorAll('.post-signature') : [];
const result = [];
sigs.forEach((sig, i) => {
  const action = sig.querySelector('.user-action-time');
  const name = sig.querySelector('.user-details a');
  result.push({
    index: i,
    action: action ? action.textContent.trim() : 'none',
    name: name ? name.textContent.trim() : 'none'
  });
});
JSON.stringify(result);
"
